func navTreeItemAttrs(navPage NavPage, activePath string, includeLinkAttrs bool, extraClasses ...string) templpkg.Attributes {
	className := "text-muted"
	if activePath == navPage.Path && !navPageContainsCurrentPageAnchor(navPage, activePath) {
		className = "menu-active"
	}
	if len(extraClasses) > 0 {
		className += " " + strings.Join(extraClasses, " ")
	}

	attrs := templpkg.Attributes{
		"class": className,
	}

	anchorID := navPageActiveAnchorID(navPage, activePath)
	if anchorID == "" {
		return attrs
	}

	activeExpression := "$_docs.activeAnchor === " + strconv.Quote(anchorID)
	attrs["data-class:menu-active"] = activeExpression
	attrs["data-class:text-muted"] = "!(" + activeExpression + ")"
	if includeLinkAttrs {
		attrs["data-attr:aria-current"] = activeExpression + " ? 'location' : null"
		attrs["data-on:click"] = "$_docs.activeAnchor = " + strconv.Quote(anchorID)
	}
	return attrs
}

func navPageContainsCurrentPageAnchor(navPage NavPage, activePath string) bool {
	if navPageActiveAnchorID(navPage, activePath) != "" {
		return true
	}
	for _, child := range navPage.Children {
		if navPageContainsCurrentPageAnchor(child, activePath) {
			return true
		}
	}
	return false
}

func navPageActiveAnchorID(navPage NavPage, activePath string) string {
	path, anchorID, ok := strings.Cut(navPage.Path, "#")
	if !ok || path != activePath {
		return ""
	}
	return anchorID
}

func navPageContainsActive(navPage NavPage, activePath string) bool {
	path, _, _ := strings.Cut(navPage.Path, "#")
	if path == activePath {
		return true
	}
	for _, child := range navPage.Children {
		if navPageContainsActive(child, activePath) {
			return true
		}
	}
	return false
}

